#   lon &lt;- as.numeric(m[6]) + as.numeric(m[7]) / 60 + as.numeric(m[8]) / 3600
#   if (m[9] == "W") lon &lt;- -lon
#   c(lat = lat, lon = lon)
# }
# coords_alaotra &lt;- gps_alaotra |&gt;
#   rename(Localisation = 5) |&gt; rowwise() |&gt;
