    )
  ) |&gt;
  count(Observatory, Proprietaire) |&gt;
  mutate(pct = round(n / sum(n) * 100, 1), .by = Observatory) |&gt;
  filter(pct &gt;= 1) |&gt;
  make_bar_obs(x = Proprietaire, y_label = "% des parcelles")








